 53→fn build_action_view(action: &NextAction, contexts: &[Context]) -> NextActionView {
 54→    let context_name = contexts
 55→        .iter()
 56→        .find(|c| c.id() == action.context_id())
 57→        .map(|c| c.name().as_str().to_string())
 58→        .unwrap_or_else(|| "Unknown".to_string());
 59→
 60→    NextActionView {
 61→        id: action.id().as_uuid().to_string(),
 62→        title: action.title().as_str().to_string(),
 63→        context_name,
 64→    }
 65→}
