 72→pub async fn get_next_actions(
 73→    AuthenticatedUser(user_id): AuthenticatedUser,
 74→    State(pool): State<PgPool>,
 75→    Query(filter): Query<ContextFilter>,
 76→) -> Result<impl IntoResponse, NextActionError> {
 77→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
 78→        .await
 79→        .map_err(NextActionError::Unexpected)?;
 80→
 81→    let contexts = context_service::list_contexts(&pool, &user_id)
 82→        .await
 83→        .map_err(NextActionError::Unexpected)?;
 84→
 85→    let actions = if let Some(ctx_uuid) = filter.context {
 86→        let ctx_id = ContextId::from_uuid(ctx_uuid);
 87→        next_action_service::list_active_next_actions_by_context(&pool, &user_id, &ctx_id)
 88→            .await
 89→            .map_err(NextActionError::Unexpected)?
 90→    } else {
 91→        next_action_service::list_active_next_actions(&pool, &user_id)
 92→            .await
 93→            .map_err(NextActionError::Unexpected)?
 94→    };
 95→
 96→    let action_views: Vec<NextActionView> = actions
 97→        .iter()
 98→        .map(|a| build_action_view(a, &contexts))
 99→        .collect();
100→
101→    let context_options: Vec<ContextOption> = contexts
102→        .iter()
103→        .map(|c| ContextOption {
104→            id: c.id().as_uuid().to_string(),
105→            name: c.name().as_str().to_string(),
106→        })
107→        .collect();
108→
109→    let selected_context = filter.context.map(|c| c.to_string());
110→
111→    let template = NextActionsTemplate {
112→        current_page: "next_actions",
113→        inbox_count,
114→        actions: action_views,
115→        contexts: context_options,
116→        selected_context,
117→        error_message: None,
118→    };
119→    Ok(Html(template.render()?))
120→}
