128→pub async fn post_next_action(
129→    AuthenticatedUser(user_id): AuthenticatedUser,
130→    State(pool): State<PgPool>,
131→    headers: HeaderMap,
132→    Form(form): Form<AddNextActionForm>,
133→) -> Result<Response, NextActionError> {
134→    let htmx = is_htmx_request(&headers);
135→
136→    if form.title.trim().is_empty() {
137→        if htmx {
138→            return Ok(StatusCode::NO_CONTENT.into_response());
139→        }
140→        return Ok(Redirect::to("/next-actions").into_response());
141→    }
142→
143→    let context_id = ContextId::from_uuid(form.context_id);
144→
145→    let contexts = context_service::list_contexts(&pool, &user_id)
146→        .await
147→        .map_err(NextActionError::Unexpected)?;
148→
149→    match next_action_service::add_next_action(&pool, user_id.clone(), context_id, form.title).await
150→    {
151→        Ok(action) => {
152→            if htmx {
153→                let template = NextActionItemTemplate {
154→                    action: build_action_view(&action, &contexts),
155→                };
156→                let body = template.render().map_err(NextActionError::Render)?;
157→                Ok(htmx_response_with_announce(Html(body), "Next action added"))
158→            } else {
159→                Ok(Redirect::to("/next-actions").into_response())
160→            }
161→        }
162→        Err(AddNextActionError::InvalidTitle(title_err)) => {
163→            let user_facing = match title_err {
164→                TodoTitleError::Empty => {
165→                    if htmx {
166→                        return Ok(StatusCode::NO_CONTENT.into_response());
167→                    }
168→                    return Ok(Redirect::to("/next-actions").into_response());
169→                }
170→                TodoTitleError::TooLong { max, .. } => {
171→                    format!("That title is too long (max {max} characters)")
172→                }
173→            };
174→
175→            render_next_actions_with_error(&pool, &user_id, &user_facing).await
176→        }
177→        Err(AddNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
178→    }
179→}
